import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);

  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);

  const [clienteNombre, setClienteNombre] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);

  // Cargar productos y clientes
  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (err) {
      console.error("Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/clientes");
      setClientes(res.data);
    } catch (err) {
      console.error("Error al obtener clientes:", err);
    }
  };

  const buscarProducto = (nombre) => {
    setBusquedaProducto(nombre);
    const producto = productos.find(
      (p) => (p.nombre || p.Nombre || "").toLowerCase() === nombre.toLowerCase()
    );
    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  const realizarVenta = async () => {
    if (!productoSeleccionado) {
      setMensaje("⚠️ Debes seleccionar un producto válido.");
      return;
    }

    if (productoSeleccionado.stock < cantidad) {
      setMensaje("❌ Stock insuficiente.");
      return;
    }

    if (!clienteNombre.trim()) {
      setMensaje("⚠️ Ingresa el nombre del cliente.");
      return;
    }

    try {
      // Buscar cliente existente o crear nuevo
      let cliente = clientes.find(
        (c) => (c.Nombre || c.nombre || "").toLowerCase() === clienteNombre.toLowerCase()
      );

      if (!cliente) {
        const nuevoCliente = await axios.post("http://localhost:5000/api/clientes", {
          Nombre: clienteNombre
        });
        cliente = nuevoCliente.data;
        setClientes([...clientes, cliente]);
      }

      // Registrar venta
      const res = await axios.post("http://localhost:5000/api/ventas", {
        ClienteID: cliente.ClienteID || cliente.id,
        productos: [
          {
            ProductID: productoSeleccionado.ProductoID || productoSeleccionado.id,
            Cantidad: cantidad,
            PrecioUnitario: productoSeleccionado.precio || productoSeleccionado.Precio
          }
        ],
        EmisorNombre: "Mi Negocio"
      });

      setTicket(res.data);
      setMensaje("✅ Venta realizada correctamente.");

      // Reset
      setBusquedaProducto("");
      setProductoSeleccionado(null);
      setClienteNombre("");
      setCantidad(1);
      obtenerProductos(); // actualizar stock
    } catch (err) {
      console.error(err);
      setMensaje("❌ Error al procesar la venta.");
    }
  };

  return (
    <div className="container mt-5">
      <div className="card shadow p-4">
        <div className="row g-3">
          {/* Producto */}
          <div className="col-md-6">
            <label className="form-label fw-semibold">Producto</label>
            <input
              type="text"
              className="form-control"
              placeholder="Buscar producto..."
              value={busquedaProducto}
              onChange={(e) => buscarProducto(e.target.value)}
              list="listaProductos"
            />
            <datalist id="listaProductos">
              {productos.map((p) => (
                <option key={p.ProductoID || p.id} value={p.Nombre || p.nombre} />
              ))}
            </datalist>
            {productoSeleccionado ? (
              productoSeleccionado.stock > 0 ? (
                <div className="mt-2 text-success">
                  ✅ En stock: {productoSeleccionado.stock} unidades
                </div>
              ) : (
                <div className="mt-2 text-danger">❌ Producto agotado</div>
              )
            ) : (
              <div className="mt-2 text-muted">🔍 Escribe para buscar</div>
            )}
          </div>

          {/* Cliente */}
          <div className="col-md-6">
            <label className="form-label fw-semibold">Cliente</label>
            <input
              type="text"
              className="form-control"
              placeholder="Nombre del cliente..."
              value={clienteNombre}
              onChange={(e) => setClienteNombre(e.target.value)}
              list="listaClientes"
            />
            <datalist id="listaClientes">
              {clientes.map((c) => (
                <option key={c.ClienteID || c.id} value={c.Nombre || c.nombre} />
              ))}
            </datalist>
          </div>

          {/* Cantidad */}
          <div className="col-md-4">
            <label className="form-label fw-semibold">Cantidad</label>
            <input
              type="number"
              min="1"
              className="form-control"
              value={cantidad}
              onChange={(e) => setCantidad(Number(e.target.value))}
            />
          </div>

          {/* Botón vender */}
          <div className="col-md-8 d-flex align-items-end">
            <button
              className="btn btn-success w-100"
              onClick={realizarVenta}
              disabled={!productoSeleccionado}
            >
              💰 Realizar Venta
            </button>
          </div>
        </div>

        {/* Mensaje */}
        {mensaje && <div className="alert alert-info text-center mt-4">{mensaje}</div>}
      </div>

      {/* Ticket */}
      {ticket && (
        <div className="card mt-5 p-4">
          <h5 className="fw-bold">🧾 Ticket de Venta</h5>
          <p>Cliente ID: {ticket.ClienteID}</p>
          <p>Emisor: {ticket.EmisorNombre}</p>
          <p>Fecha: {new Date(ticket.Fecha).toLocaleString()}</p>
          <p>Numero Secuencia: {ticket.NumeroSecuencia}</p>

          <table className="table table-bordered mt-3">
            <thead>
              <tr>
                <th>Producto</th>
                <th>Cantidad</th>
                <th>Precio Unitario</th>
                <th>Subtotal</th>
              </tr>
            </thead>
            <tbody>
              {ticket.productos.map((p, idx) => {
                const producto = productos.find(prod => (prod.ProductoID || prod.id) === p.ProductID);
                return (
                  <tr key={idx}>
                    <td>{producto ? producto.Nombre || producto.nombre : p.ProductID}</td>
                    <td>{p.Cantidad}</td>
                    <td>{p.PrecioUnitario.toFixed(2)}</td>
                    <td>{(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          <p>Subtotal: {ticket.Subtotal.toFixed(2)}</p>
          <p>IVA: {ticket.IVA.toFixed(2)}</p>
          <p>Total: {ticket.Total.toFixed(2)}</p>
        </div>
      )}
    </div>
  );
}
